using CommunityToolkit.Mvvm.ComponentModel;
using CommunityToolkit.Mvvm.Input;

namespace KmgAssets.ViewModels;

public partial class AddAssetVM : ObservableObject
{
    [ObservableProperty] [NotifyCanExecuteChangedFor(nameof(SaveCommand))]
    private string _name = string.Empty;

    [ObservableProperty] [NotifyCanExecuteChangedFor(nameof(SaveCommand))]
    private string _department = string.Empty;

    [ObservableProperty] [NotifyCanExecuteChangedFor(nameof(SaveCommand))]
    private int _amount;

    [ObservableProperty] private string? _nameError;
    [ObservableProperty] private string? _departmentError;
    [ObservableProperty] private string? _amountError;

    [ObservableProperty] private bool _isBusy;

    [RelayCommand(CanExecute = nameof(CanSave))]
    private async Task SaveAsync()
    {
        if (!Validate()) return;
        try
        {
            IsBusy = true;
            await Task.Delay(300); // имитация БД
            await Shell.Current.GoToAsync("..");
        }
        finally { IsBusy = false; }
    }

    private bool CanSave() =>
        !IsBusy
        && !string.IsNullOrWhiteSpace(Name)
        && !string.IsNullOrWhiteSpace(Department)
        && Amount > 0;

    private bool Validate()
    {
        NameError       = string.IsNullOrWhiteSpace(Name)       ? "Имя обязательно" :
                          Name.Length > 100                     ? "Максимум 100 символов" : null;
        DepartmentError = string.IsNullOrWhiteSpace(Department) ? "Выберите департамент" : null;
        AmountError     = Amount <= 0                           ? "Количество должно быть > 0" : null;

        return NameError is null && DepartmentError is null && AmountError is null;
    }
}

[RelayCommand]
private async Task CancelAsync()
{
    var hasData = !string.IsNullOrWhiteSpace(Name)
                || !string.IsNullOrWhiteSpace(Department)
                || Amount > 0;

    if (hasData)
    {
        var ok = await Shell.Current.DisplayAlert(
            "Отмена", "Несохранённые данные будут потеряны. Продолжить?",
            "Да", "Нет");
        if (!ok) return;
    }

    await Shell.Current.GoToAsync("..");
}
